import React, { useCallback, useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { X, Search, Plus, CheckCircle, AlertCircle, Filter, UserPlus } from "lucide-react";
import "./Dashboard.css";
import "../../App.css";
import api from "../../api";

export default function CreatePage() {
  const navigate = useNavigate();

  const [title,           setTitle]       = useState("");
  const [description,     setDesc]        = useState("");
  const [crimeDate,       setCrimeDate]   = useState("");
  const [startDate,       setStartDate]   = useState("");
  const [priority,        setPriority]    = useState("High");
  const [status,          setStatus]      = useState("Open");
  const [leader,          setLeader]      = useState("");
  const [leaders,         setLeaders]     = useState([]);
  const [searchTerm,      setSearch]      = useState("");
  const [roleFilter,      setRoleFilter]  = useState("");
  const [regionFilter,    setRegionFilter]= useState("");
  const [searchResults,   setResults]     = useState([]);
  const [assignedMembers, setMembers]     = useState([]);
  const [submitting,      setSubmitting]  = useState(false);
  const [msg,             setMsg]         = useState({ type: "", text: "" });
  const [roles,           setRoles]       = useState([]);
  const [regions,         setRegions]     = useState([]);

  const flash = (type, text) => {
    setMsg({ type, text });
    if (type === "success") {
      setTimeout(() => navigate("/cases"), 1800);
    } else {
      setTimeout(() => setMsg({ type: "", text: "" }), 4000);
    }
  };

  useEffect(() => {
    const load = async () => {
      try {
        const [leadsRes, rolesRes, regionsRes] = await Promise.all([
          api.get("/users/leads"),
          api.get("/roles"),
          api.get("/regions"),
        ]);
        setLeaders(Array.isArray(leadsRes.data) ? leadsRes.data : []);
        setRoles(Array.isArray(rolesRes.data) ? rolesRes.data : []);
        setRegions(Array.isArray(regionsRes.data) ? regionsRes.data : []);
      } catch (err) {
        console.error("Error fetching setup data:", err);
      }
    };
    load();
  }, []);

  const handleSearch = useCallback(async () => {
    if (!searchTerm && !roleFilter && !regionFilter) { setResults([]); return; }
    try {
      const params = new URLSearchParams();
      if (searchTerm)  params.append("q",      searchTerm);
      if (roleFilter)  params.append("role",   roleFilter);
      if (regionFilter)params.append("region", regionFilter);
      const res = await api.get(`/users/search?${params}`);
      const existingIds = new Set(assignedMembers.map((m) => m._id));
      setResults((Array.isArray(res.data) ? res.data : []).filter((u) => !existingIds.has(u._id)));
    } catch { setResults([]); }
  }, [searchTerm, roleFilter, regionFilter, assignedMembers]);

  useEffect(() => { handleSearch(); }, [handleSearch]);

  const addMember = (member) => {
    if (!assignedMembers.find((m) => m._id === member._id))
      setMembers((prev) => [...prev, member]);
    setSearch("");
    setResults([]);
  };

  const removeMember = (id) => setMembers((prev) => prev.filter((m) => m._id !== id));

  const handleCreate = async () => {
    if (!title.trim())       return flash("error", "Case title is required");
    if (!description.trim()) return flash("error", "Description is required");
    setSubmitting(true);
    try {
      await api.post("/create-case", {
        title:       title.trim(),
        description: description.trim(),
        status,
        priority,
        start_date:  startDate  ? new Date(startDate).toISOString()  : new Date().toISOString(),
        crime_date:  crimeDate  ? new Date(crimeDate).toISOString()  : undefined,
        leader_id:   leader     || undefined,
        member_ids:  assignedMembers.map((m) => m._id),
      });
      flash("success", "Case created successfully! Redirecting...");
    } catch (err) {
      flash("error", err.response?.data?.message || "Failed to create case");
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="dashboardMain">
      {/* Header */}
      <header className="dashboardHeader">
        <div className="headerBranding">
          <h1 className="logoText"><span>LEGALLENS</span> Create Case</h1>
          <p className="systemStatus">Fill in the details to open a new investigation case</p>
        </div>
      </header>

      {/* Alert */}
      {msg.text && (
        <div className={`alertBanner ${msg.type === "success" ? "alertSuccess" : "alertError"}`}
          style={{ display:"flex", alignItems:"center", gap:"0.5rem", marginBottom:"1.5rem" }}>
          {msg.type === "success" ? <CheckCircle size={16} /> : <AlertCircle size={16} />}
          {msg.text}
        </div>
      )}

      {/* ── Three-panel horizontal layout ── */}
      <div className="createCaseGrid">

        {/* ─── Panel 1: Case Details ─── */}
        <div className="createCasePanel">
          <div className="sectionHeader">
            <div className="indicatorDot" style={{ background:"#3b82f6" }} />
            <h2>CASE DETAILS</h2>
          </div>
          <div className="createCasePanelBody">
            <div className="inputGroup" style={{ gridColumn:"span 2" }}>
              <label>Case Title *</label>
              <input type="text" placeholder="e.g. Downtown Bank Robbery"
                value={title} onChange={(e) => setTitle(e.target.value)} />
            </div>
            <div className="inputGroup" style={{ gridColumn:"span 2" }}>
              <label>Description *</label>
              <textarea placeholder="Describe the case in detail..."
                value={description} onChange={(e) => setDesc(e.target.value)}
                rows={4} style={{ resize:"vertical" }} />
            </div>
            <div className="inputGroup">
              <label>Date of Crime</label>
              <input type="date" value={crimeDate} onChange={(e) => setCrimeDate(e.target.value)} />
            </div>
            <div className="inputGroup">
              <label>Case Start Date</label>
              <input type="date" value={startDate}
                max={new Date().toISOString().split("T")[0]}
                onChange={(e) => setStartDate(e.target.value)} />
            </div>
          </div>
        </div>

        {/* ─── Panel 2: Assign Members ─── */}
        <div className="createCasePanel">
          <div className="sectionHeader">
            <div className="indicatorDot" style={{ background:"#34d399" }} />
            <h2>ASSIGN MEMBERS</h2>
          </div>
          <div className="createCasePanelBody">
            {/* Filter row */}
            <div className="createFilterRow">
              <div className="inputGroup" style={{ flex:1 }}>
                <label>Filter by Role</label>
                <select value={roleFilter} onChange={(e) => setRoleFilter(e.target.value)}
                  className="createFilterSelect">
                  <option value="">All Roles</option>
                  {roles.map((r) => (
                    <option key={r._id} value={r.role_name}>{r.role_name.replace(/_/g," ")}</option>
                  ))}
                </select>
              </div>
              <div className="inputGroup" style={{ flex:1 }}>
                <label>Filter by Region</label>
                <select value={regionFilter} onChange={(e) => setRegionFilter(e.target.value)}
                  className="createFilterSelect">
                  <option value="">All Regions</option>
                  {regions.map((r) => <option key={r} value={r}>{r}</option>)}
                </select>
              </div>
              {(roleFilter || regionFilter) && (
                <button type="button" className="createFilterClear"
                  onClick={() => { setRoleFilter(""); setRegionFilter(""); }}
                  title="Clear filters">
                  <X size={14} />
                </button>
              )}
            </div>

            {/* Search */}
            <div className="inputGroup">
              <label>Search Members</label>
              <div className="membersSearch">
                <Search size={16} color="#475569" />
                <input type="text" placeholder="Search by name..."
                  value={searchTerm} onChange={(e) => setSearch(e.target.value)}
                  style={{ background:"transparent", border:"none", outline:"none", color:"#fff", fontSize:"0.875rem", flex:1 }} />
                {searchTerm && (
                  <button type="button" onClick={() => setSearch("")}
                    style={{ background:"none", border:"none", cursor:"pointer", color:"#64748b" }}>
                    <X size={14} />
                  </button>
                )}
              </div>
            </div>

            {/* Results */}
            {searchResults.length > 0 && (
              <div className="createSearchResults">
                {searchResults.map((u) => (
                  <div key={u._id} className="createSearchItem">
                    <div className="avatarCircle" style={{ width:32, height:32, fontSize:11 }}>
                      {u.name?.charAt(0)?.toUpperCase()}
                    </div>
                    <div style={{ flex:1, minWidth:0 }}>
                      <p style={{ margin:0, fontWeight:600, fontSize:"0.85rem", color:"#e2e8f0" }}>{u.name}</p>
                      <p style={{ margin:0, color:"#64748b", fontSize:"0.75rem" }}>
                        {u.role_id?.role_name?.replace(/_/g," ")} {u.Region ? `· ${u.Region}` : ""}
                      </p>
                    </div>
                    <button type="button" className="createAddBtn" onClick={() => addMember(u)}>
                      <Plus size={13} /> Add
                    </button>
                  </div>
                ))}
              </div>
            )}
            {searchTerm && searchResults.length === 0 && (
              <p style={{ color:"#475569", fontSize:"0.8rem", marginTop:"0.5rem" }}>No members found.</p>
            )}

            {/* Lead */}
            <div className="inputGroup" style={{ marginTop:"0.75rem" }}>
              <label>Assigned Lead Investigator</label>
              <select value={leader} onChange={(e) => setLeader(e.target.value)}
                style={{ background:"#1e293b", border:"1px solid rgba(255,255,255,0.08)", color:"#fff",
                  padding:"0.75rem 1rem", borderRadius:8, fontSize:"0.9rem", width:"100%" }}>
                <option value="">— Select Lead Investigator —</option>
                {leaders.map((l) => <option key={l._id} value={l._id}>{l.name}</option>)}
              </select>
            </div>

            {/* Assigned chips */}
            {assignedMembers.length > 0 && (
              <div style={{ marginTop:"1rem" }}>
                <p style={{ fontSize:"0.78rem", color:"#94a3b8", textTransform:"uppercase", letterSpacing:"0.08em", margin:"0 0 0.5rem", fontWeight:700 }}>
                  Assigned ({assignedMembers.length})
                </p>
                <div style={{ display:"flex", flexWrap:"wrap", gap:"0.4rem" }}>
                  {assignedMembers.map((m) => (
                    <span key={m._id} className="memberChip">
                      {m.name}
                      <button type="button" onClick={() => removeMember(m._id)} className="memberChipRemove">
                        <X size={11} />
                      </button>
                    </span>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* ─── Panel 3: Settings + Submit ─── */}
        <div className="createCasePanel">
          <div className="sectionHeader">
            <div className="indicatorDot" style={{ background:"#f59e0b" }} />
            <h2>CASE SETTINGS</h2>
          </div>
          <div className="createCasePanelBody">
            <div className="inputGroup">
              <label>Priority</label>
              <select value={priority} onChange={(e) => setPriority(e.target.value)}
                style={{ background:"#1e293b", border:"1px solid rgba(255,255,255,0.08)", color:"#fff",
                  padding:"0.75rem 1rem", borderRadius:8, fontSize:"0.9rem", width:"100%" }}>
                <option value="High">🔴 High</option>
                <option value="Medium">🟡 Medium</option>
                <option value="Low">🟢 Low</option>
              </select>
            </div>
            <div className="inputGroup">
              <label>Initial Status</label>
              <select value={status} onChange={(e) => setStatus(e.target.value)}
                style={{ background:"#1e293b", border:"1px solid rgba(255,255,255,0.08)", color:"#fff",
                  padding:"0.75rem 1rem", borderRadius:8, fontSize:"0.9rem", width:"100%" }}>
                <option value="Open">Open</option>
                <option value="Close">Closed</option>
                <option value="Archived">Archived</option>
              </select>
            </div>

            {/* Summary box */}
            <div className="createSummaryBox">
              <p className="createSummaryTitle">Summary</p>
              <div className="createSummaryRow">
                <span>Title</span>
                <span>{title.trim() || <em style={{ color:"#334155" }}>Not set</em>}</span>
              </div>
              <div className="createSummaryRow">
                <span>Priority</span>
                <span style={{ color: priority==="High"?"#f87171":priority==="Medium"?"#fbbf24":"#34d399" }}>
                  {priority}
                </span>
              </div>
              <div className="createSummaryRow">
                <span>Status</span>
                <span style={{ color:"#34d399" }}>{status}</span>
              </div>
              <div className="createSummaryRow">
                <span>Members</span>
                <span style={{ color:"#818cf8" }}>{assignedMembers.length} assigned</span>
              </div>
            </div>

            {/* Action buttons */}
            <div className="createActionRow">
              <button type="button" className="btnCancel"
                style={{ flex:1, padding:"0.875rem 0" }}
                onClick={() => navigate("/cases")} disabled={submitting}>
                Cancel
              </button>
              <button type="button" className="btnCreate"
                style={{ flex:2, padding:"0.875rem 0" }}
                onClick={handleCreate} disabled={submitting}>
                {submitting ? "Creating..." : <><Plus size={16} />Create Case</>}
              </button>
            </div>
          </div>
        </div>

      </div>{/* end createCaseGrid */}
    </div>
  );
}
